phase1.code:
import java.io.*;

// Serializable class
class Person implements Serializable {
    // Serial version UID — ensures compatibility
    private static final long serialVersionUID = 1L;

    private String name;
    private int age;
    private String email;

    // transient — won't be serialized
    private transient String password;

    // Static fields aren't serialized
    private static String company = "Acme Corp";

    Person(String name, int age, String email, String password) {
        this.name = name;
        this.age = age;
        this.email = email;
        this.password = password;
    }

    @Override
    public String toString() {
        return "Person{name='" + name + "', age=" + age + 
               ", email='" + email + "', password='" + password + 
               "', company='" + company + "'}";
    }
}

public class SerializationExample {
    public static void main(String[] args) {
        Person alice = new Person("Alice", 25, "alice@email.com", "secret123");

        System.out.println("=== Serialization ===");
        System.out.println("Original: " + alice);

        // Serialize (write to file)
        String filename = "person.ser";
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(filename))) {
            oos.writeObject(alice);
            System.out.println("Object serialized to " + filename);
        } catch (IOException e) {
            System.out.println("Serialization error: " + e.getMessage());
        }

        // Deserialize (read from file)
        System.out.println("=== Deserialization ===");
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(filename))) {
            Person restored = (Person) ois.readObject();
            System.out.println("Restored: " + restored);

            // Check transient field
            System.out.println("Password: " + restored.toString());
        } catch (IOException | ClassNotFoundException e) {
            System.out.println("Deserialization error: " + e.getMessage());
        }

        // Serializing multiple objects
        System.out.println("=== Multiple Objects ===");
        Person[] people = {
            new Person("Bob", 30, "bob@email.com", "pass1"),
            new Person("Charlie", 35, "charlie@email.com", "pass2")
        };

        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream("people.ser"))) {
            oos.writeObject(people);
            System.out.println("Array serialized!");
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }

        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream("people.ser"))) {
            Person[] restoredPeople = (Person[]) ois.readObject();
            System.out.println("Restored array:");
            for (Person p : restoredPeople) {
                System.out.println("  " + p);
            }
        } catch (IOException | ClassNotFoundException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}

